SpinningCube	A Three.js animated spinning 3D cube with customizable size, colors, and rotation speed.	{threejs,3d,animation,webgl,canvas,cube}	three	import { z } from "zod";\n\nexport const schema = z.object({\n  size: z.number().min(50).max(600).default(400).describe("Canvas size in pixels"),\n  cubeColor: z.string().default("#6366f1").describe("Main face color of the cube"),\n  wireframeColor: z.string().default("#a5b4fc").describe("Wireframe edge color"),\n  backgroundColor: z.string().default("#0f0f1a").describe("Background color"),\n  rotationSpeed: z.number().min(0.1).max(5).default(1).describe("Rotation speed multiplier"),\n  showWireframe: z.boolean().default(true).describe("Overlay a wireframe on the cube"),\n});\n\nexport type Props = z.infer<typeof schema>;	"use client";\n\nimport { useEffect, useRef } from "react";\nimport * as THREE from "three";\nimport type { Props } from "./schema";\n\nexport function Component({\n  size = 400,\n  cubeColor = "#6366f1",\n  wireframeColor = "#a5b4fc",\n  backgroundColor = "#0f0f1a",\n  rotationSpeed = 1,\n  showWireframe = true,\n}: Props) {\n  const mountRef = useRef<HTMLDivElement>(null);\n\n  useEffect(() => {\n    const mount = mountRef.current;\n    if (!mount) return;\n\n    const renderer = new THREE.WebGLRenderer({ antialias: true });\n    renderer.setPixelRatio(window.devicePixelRatio);\n    renderer.setSize(size, size);\n    renderer.setClearColor(new THREE.Color(backgroundColor));\n    mount.appendChild(renderer.domElement);\n\n    const scene = new THREE.Scene();\n    const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);\n    camera.position.set(2.5, 2, 3);\n    camera.lookAt(0, 0, 0);\n\n    const geometry = new THREE.BoxGeometry(1.5, 1.5, 1.5);\n\n    const faceColors = [\n      new THREE.Color(cubeColor),\n      new THREE.Color(cubeColor).offsetHSL(0.05, 0, -0.1),\n      new THREE.Color(cubeColor).offsetHSL(0.1, 0, 0.05),\n      new THREE.Color(cubeColor).offsetHSL(-0.05, 0, -0.05),\n      new THREE.Color(cubeColor).offsetHSL(0.15, 0, 0.1),\n      new THREE.Color(cubeColor).offsetHSL(-0.1, 0, -0.15),\n    ];\n    const materials = faceColors.map(\n      (color) =>\n        new THREE.MeshStandardMaterial({\n          color,\n          roughness: 0.35,\n          metalness: 0.6,\n        })\n    );\n\n    const cube = new THREE.Mesh(geometry, materials);\n    scene.add(cube);\n\n    if (showWireframe) {\n      const wireGeo = new THREE.EdgesGeometry(geometry);\n      const wireMat = new THREE.LineBasicMaterial({\n        color: new THREE.Color(wireframeColor),\n        linewidth: 2,\n      });\n      const wireframe = new THREE.LineSegments(wireGeo, wireMat);\n      cube.add(wireframe);\n    }\n\n    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);\n    scene.add(ambientLight);\n\n    const dirLight = new THREE.DirectionalLight(0xffffff, 1.2);\n    dirLight.position.set(5, 8, 5);\n    scene.add(dirLight);\n\n    const pointLight = new THREE.PointLight(0xa78bfa, 1.5, 20);\n    pointLight.position.set(-4, -2, 3);\n    scene.add(pointLight);\n\n    let frameId: number;\n    const speed = rotationSpeed * 0.005;\n\n    const animate = () => {\n      frameId = requestAnimationFrame(animate);\n      cube.rotation.x += speed * 1.1;\n      cube.rotation.y += speed * 1.7;\n      cube.rotation.z += speed * 0.4;\n      renderer.render(scene, camera);\n    };\n    animate();\n\n    return () => {\n      cancelAnimationFrame(frameId);\n      renderer.dispose();\n      geometry.dispose();\n      materials.forEach((m) => m.dispose());\n      if (mount.contains(renderer.domElement)) {\n        mount.removeChild(renderer.domElement);\n      }\n    };\n  }, [size, cubeColor, wireframeColor, backgroundColor, rotationSpeed, showWireframe]);\n\n  return (\n    <div\n      ref={mountRef}\n      style={{\n        width: size,\n        height: size,\n        maxWidth: "100%",\n        borderRadius: 12,\n        overflow: "hidden",\n        display: "inline-block",\n      }}\n    />\n  );\n}	2026-06-13 19:36:54.031389+00
SpinningCubeLit	A Three.js spinning 3D cube with dynamic lighting (ambient + point lights) and a bounce animation.	{threejs,3d,animation,webgl,cube,lights,bounce}	three	\nimport { z } from "zod";\n\nexport const schema = z.object({\n  size: z.number().default(420).describe("Canvas size in px"),\n  cubeColor: z.string().default("#6366f1").describe("Cube face color"),\n  wireframeColor: z.string().default("#a5b4fc").describe("Wireframe edge color"),\n  backgroundColor: z.string().default("#0f0f1a").describe("Canvas background color"),\n  rotationSpeed: z.number().default(1.2).describe("Rotation speed multiplier"),\n  showWireframe: z.boolean().default(true).describe("Show wireframe overlay"),\n  bounceSpeed: z.number().default(1.5).describe("Bounce speed multiplier"),\n  bounceHeight: z.number().default(0.6).describe("Bounce height in Three.js units"),\n  lightColor: z.string().default("#ffffff").describe("Point light color"),\n  lightIntensity: z.number().default(2).describe("Point light intensity"),\n});\n\nexport type Props = z.infer<typeof schema>;\n	\n"use client";\nimport { useEffect, useRef } from "react";\nimport * as THREE from "three";\nimport type { Props } from "./schema";\n\nexport function Component({\n  size = 420,\n  cubeColor = "#6366f1",\n  wireframeColor = "#a5b4fc",\n  backgroundColor = "#0f0f1a",\n  rotationSpeed = 1.2,\n  showWireframe = true,\n  bounceSpeed = 1.5,\n  bounceHeight = 0.6,\n  lightColor = "#ffffff",\n  lightIntensity = 2,\n}: Props) {\n  const mountRef = useRef<HTMLDivElement>(null);\n\n  useEffect(() => {\n    const mount = mountRef.current;\n    if (!mount) return;\n\n    // Scene\n    const scene = new THREE.Scene();\n    scene.background = new THREE.Color(backgroundColor);\n\n    // Camera\n    const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);\n    camera.position.set(0, 0, 4);\n\n    // Renderer\n    const renderer = new THREE.WebGLRenderer({ antialias: true });\n    renderer.setSize(size, size);\n    renderer.shadowMap.enabled = true;\n    renderer.shadowMap.type = THREE.PCFSoftShadowMap;\n    mount.appendChild(renderer.domElement);\n\n    // Lights\n    const ambientLight = new THREE.AmbientLight(0xffffff, 0.4);\n    scene.add(ambientLight);\n\n    const pointLight1 = new THREE.PointLight(new THREE.Color(lightColor).getHex(), lightIntensity, 20);\n    pointLight1.position.set(4, 4, 4);\n    pointLight1.castShadow = true;\n    scene.add(pointLight1);\n\n    const pointLight2 = new THREE.PointLight(0x818cf8, lightIntensity * 0.6, 20);\n    pointLight2.position.set(-4, -2, 3);\n    scene.add(pointLight2);\n\n    const rimLight = new THREE.DirectionalLight(0xa5b4fc, 0.8);\n    rimLight.position.set(0, -4, -2);\n    scene.add(rimLight);\n\n    // Light helpers (moving point light glow)\n    const lightSphere1 = new THREE.Mesh(\n      new THREE.SphereGeometry(0.08, 8, 8),\n      new THREE.MeshBasicMaterial({ color: lightColor })\n    );\n    lightSphere1.position.copy(pointLight1.position);\n    scene.add(lightSphere1);\n\n    // Cube (Phong for shiny lighting)\n    const geometry = new THREE.BoxGeometry(1.5, 1.5, 1.5);\n    const material = new THREE.MeshPhongMaterial({\n      color: new THREE.Color(cubeColor),\n      shininess: 80,\n      specular: new THREE.Color(0xffffff),\n    });\n    const cube = new THREE.Mesh(geometry, material);\n    cube.castShadow = true;\n    scene.add(cube);\n\n    // Wireframe overlay\n    let wireMesh: THREE.LineSegments | null = null;\n    if (showWireframe) {\n      const wireGeo = new THREE.EdgesGeometry(geometry);\n      const wireMat = new THREE.LineBasicMaterial({ color: new THREE.Color(wireframeColor), linewidth: 1 });\n      wireMesh = new THREE.LineSegments(wireGeo, wireMat);\n      cube.add(wireMesh);\n    }\n\n    // Floor (subtle shadow catcher)\n    const floorGeo = new THREE.PlaneGeometry(10, 10);\n    const floorMat = new THREE.ShadowMaterial({ opacity: 0.3 });\n    const floor = new THREE.Mesh(floorGeo, floorMat);\n    floor.rotation.x = -Math.PI / 2;\n    floor.position.y = -2;\n    floor.receiveShadow = true;\n    scene.add(floor);\n\n    // Animation loop\n    let animId: number;\n    const clock = new THREE.Clock();\n\n    const animate = () => {\n      animId = requestAnimationFrame(animate);\n      const t = clock.getElapsedTime();\n\n      // Rotation\n      cube.rotation.x += 0.008 * rotationSpeed;\n      cube.rotation.y += 0.012 * rotationSpeed;\n\n      // Bounce: smooth sine wave\n      cube.position.y = Math.abs(Math.sin(t * bounceSpeed * Math.PI)) * bounceHeight - bounceHeight * 0.3;\n\n      // Orbit point light 1 for dynamic highlight\n      pointLight1.position.x = Math.sin(t * 0.8) * 4;\n      pointLight1.position.z = Math.cos(t * 0.8) * 4;\n      lightSphere1.position.copy(pointLight1.position);\n\n      renderer.render(scene, camera);\n    };\n    animate();\n\n    return () => {\n      cancelAnimationFrame(animId);\n      renderer.dispose();\n      if (mount.contains(renderer.domElement)) {\n        mount.removeChild(renderer.domElement);\n      }\n    };\n  }, [size, cubeColor, wireframeColor, backgroundColor, rotationSpeed, showWireframe, bounceSpeed, bounceHeight, lightColor, lightIntensity]);\n\n  return (\n    <div\n      ref={mountRef}\n      style={{\n        width: size,\n        height: size,\n        maxWidth: "100%",\n        borderRadius: 12,\n        overflow: "hidden",\n        display: "inline-block",\n      }}\n    />\n  );\n}\n	2026-06-13 19:50:21.636928+00
