[credits, setCredits] = React.useState(props.startCredits ?? 48320);\n  const [hops,    setHops]    = React.useState(props.startProxyHops ?? 4);\n  const [busted,  setBusted]  = React.useState(false);\n  const [mProg,   setMProg]   = React.useState({arc:0,rec:0,neura:0,aeon:0});\n  const [mDone,   setMDone]   = React.useState({arc:false,rec:false,neura:false,aeon:false});\n  const [log,     setLog]     = React.useState([\n    '════════════════════════════════════════════',\n    '  UPLINK OS v4.2.1 — Internic Global Network',\n    '════════════════════════════════════════════',\n    `  Agent: ${props.agentName ?? 'GH0ST_R1DER'} | Clearance: BLACK`,\n    '  Proxy: [TOR] → [NL-RELAY] → [US-EXIT] → [UPLINK]',\n    '  ⚠ Trace at 38% — reroute recommended.',\n    '',\n    "  Type 'help' for commands or use quick-action buttons.",\n    '',\n  ]);\n  const [input,   setInput]   = React.useState('');\n  const [hist,    setHist]    = React.useState([]);\n  const [histIdx, setHistIdx] = React.useState(-1);\n  const bottomRef = React.useRef(null);\n\n  // refs for stable closures\n  const traceRef   = React.useRef(trace);   traceRef.current   = trace;\n  const credRef    = React.useRef(credits); credRef.current    = credits;\n  const hopsRef    = React.useRef(hops);    hopsRef.current    = hops;\n  const mProgRef   = React.useRef(mProg);   mProgRef.current   = mProg;\n  const mDoneRef   = React.useRef(mDone);   mDoneRef.current   = mDone;\n\n  // ── live trace tick ────────────────────────────────────────\n  React.useEffect(() => {\n    if (busted) return;\n    const id = setInterval(() => {\n      setTrace(t => {\n        const n = parseFloat((t + 0.08).toFixed(2));\n        if (n >= 100) { setBusted(true); return 100; }\n        return n;\n      });\n    }, 1000);\n    return () => clearInterval(id);\n  }, [busted]);\n\n  React.useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:'smooth' }); }, [log]);\n\n  const push = lines => setLog(l => [...l, ...lines, '']);\n\n  function tBar(pct) {\n    const f = Math.min(10, Math.round(pct / 10));\n    return '  [' + '█'.repeat(f) + '░'.repeat(10 - f) + `] ${pct.toFixed(1)}%`;\n  }\n\n  // ── command engine ─────────────────────────────────────────\n  function run(verb, args) {\n    if (verb === 'help') {\n      push([\n        '  ┌─ COMMANDS ──────────────────────────────────────────┐',\n        '  │  connect <ip>   route to target server              │',\n        '  │  crack <svc>    crack ssh / ftp / http              │',\n        '  │  hack <target>  full 4-stage breach                 │',\n        '  │  ls             list files on current server        │',\n        '  │  trace          show live trace status + ETA        │',\n        '  │  reroute        reset proxy (−15–25% trace)         │',\n        '  │  bounty         list available contracts            │',\n        '  │  mission <id>   advance mission arc/rec/neura/aeon  │',\n        '  │  credits        show balance                        │',\n        '  │  whoami         agent identity                      │',\n        '  │  clear          clear terminal                      │',\n        '  └──────────────────────────────────────────────────────┘',\n      ]);\n    } else if (verb === 'whoami') {\n      push([\n        `  Agent    : ${props.agentName ?? 'GH0ST_R1DER'}`,\n        '  Rank     : ELITE (#47)',\n        `  Credits  : ¢ ${credRef.current.toLocaleString()}`,\n        `  Proxy    : ${hopsRef.current} active hops`,\n        `  Trace    : ${traceRef.current.toFixed(1)}%`,\n        '  Clearance: BLACK',\n        `  Missions : ${Object.values(mDoneRef.current).filter(Boolean).length}/${MISSIONS.length} complete`,\n      ]);\n    } else if (verb === 'credits') {\n      push([`  ¢ ${credRef.current.toLocaleString()} — ${credRef.current > 50000 ? 'FLUSH' : credRef.current > 20000 ? 'STABLE' : 'LOW FUNDS'}` ]);\n    } else if (verb === 'ls') {\n      push([\n        '  /sys   /logs   /data   /encrypted   /tools',\n      